  1→/**
  2→ * FileRepository - CRUD operations for FileEntity model
  3→ *
  4→ * Provides typed methods for FileEntity queries with soft-delete support.
  5→ * All errors propagate to caller for handling at API layer.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  FileEntity,
 11→  Prisma,
 12→} from '@prisma/client';
 13→import { randomUUID } from 'node:crypto';
 14→
 15→/**
 16→ * FileEntity creation input type
 17→ */
 18→export type FileCreateInput = Omit<Prisma.FileEntityUncheckedCreateInput, 'id'> & Partial<Pick<Prisma.FileEntityUncheckedCreateInput, 'id'>>;
 19→
 20→/**
 21→ * FileEntity update input type
 22→ */
 23→export type FileUpdateInput = Prisma.FileEntityUncheckedUpdateInput;
 24→
 25→/**
 26→ * FileEntity findMany params type
 27→ */
 28→export type FileFindManyParams = {
 29→  where?: Prisma.FileEntityWhereInput;
 30→  orderBy?: Prisma.FileEntityOrderByWithRelationInput;
 31→  skip?: number;
 32→  take?: number;
 33→  include?: Prisma.FileEntityInclude;
 34→};
 35→
 36→/**
 37→ * Repository for FileEntity CRUD operations
 38→ */
 39→export class FileRepository {
 40→  /**
 41→   * Find many files with optional filtering
 42→   * Automatically filters out soft-deleted records
 43→   */
 44→  async findMany(params?: FileFindManyParams): Promise<FileEntity[]> {
 45→    const { where, ...rest } = params ?? {};
 46→
 47→    return prisma.fileEntity.findMany({
 48→      ...rest,
 49→      where: {
 50→        ...where,
 51→        deletedAt: null, // Always exclude soft-deleted
 52→      },
 53→    });
 54→  }
 55→
 56→  /**
 57→   * Find a single file by ID
 58→   * Returns null if not found or soft-deleted
 59→   */
 60→  async findUnique(
 61→    id: string,
 62→    include?: Prisma.FileEntityInclude
 63→  ): Promise<FileEntity | null> {
 64→    return prisma.fileEntity.findFirst({
 65→      where: { id, deletedAt: null },
 66→      include,
 67→    });
 68→  }
 69→
 70→  /**
 71→   * Find a single file by storage key
 72→   * Returns null if not found or soft-deleted
 73→   */
 74→  async findByStorageKey(storageKey: string): Promise<FileEntity | null> {
 75→    return prisma.fileEntity.findFirst({
 76→      where: { storageKey, deletedAt: null },
 77→    });
 78→  }
 79→
 80→  /**
 81→   * Find files uploaded by a specific user
 82→   */
 83→  async findByUploader(userId: string): Promise<FileEntity[]> {
 84→    return prisma.fileEntity.findMany({
 85→      where: { uploadedBy: userId, deletedAt: null },
 86→      orderBy: { createdAt: 'desc' },
 87→    });
 88→  }
 89→
 90→  /**
 91→   * Create a new file record
 92→   * Generates UUID if not provided
 93→   * Note: createdAt has @default(now()) in schema
 94→   */
 95→  async create(data: FileCreateInput): Promise<FileEntity> {
 96→    return prisma.fileEntity.create({
 97→      data: {
 98→        ...data,
 99→        id: data.id ?? randomUUID(),
100→      },
101→    });
102→  }
103→
104→  /**
105→   * Update an existing file
106→   * Throws RecordNotFound if file doesn't exist or is soft-deleted
107→   */
108→  async update(
109→    id: string,
110→    data: FileUpdateInput
111→  ): Promise<FileEntity> {
112→    // Verify file exists and not deleted
113→    const existing = await this.findUnique(id);
114→    if (!existing) {
115→      throw new Error(`FileEntity with id ${id} not found`);
116→    }
117→
118→    return prisma.fileEntity.update({
119→      where: { id },
120→      data,
121→    });
122→  }
123→
124→  /**
125→   * Soft delete a file by setting deletedAt timestamp
126→   * Does NOT actually delete the record from database
127→   */
128→  async softDelete(id: string): Promise<FileEntity> {
129→    // Verify file exists and not already deleted
130→    const existing = await this.findUnique(id);
131→    if (!existing) {
132→      throw new Error(`FileEntity with id ${id} not found`);
133→    }
134→
135→    return prisma.fileEntity.update({
136→      where: { id },
137→      data: { deletedAt: new Date() },
138→    });
139→  }
140→
141→  /**
142→   * Hard delete a file (permanently remove from database)
143→   * Use with caution - typically called after storage cleanup
144→   */
145→  async hardDelete(id: string): Promise<FileEntity> {
146→    const existing = await prisma.fileEntity.findUnique({
147→      where: { id },
148→    });
149→    if (!existing) {
150→      throw new Error(`FileEntity with id ${id} not found`);
151→    }
152→
153→    return prisma.fileEntity.delete({
154→      where: { id },
155→    });
156→  }
157→
158→  /**
159→   * Count files matching criteria (excluding soft-deleted)
160→   */
161→  async count(where?: Prisma.FileEntityWhereInput): Promise<number> {
162→    return prisma.fileEntity.count({
163→      where: {
164→        ...where,
165→        deletedAt: null,
166→      },
167→    });
168→  }
169→}
170→
171→/**
172→ * Singleton instance for use across the application
173→ */
174→export const files = new FileRepository();
175→
176→export default files;
